import math


def hypotenuse(a, b):
    return math.hypot(a, b)


def degrees_to_radians(deg):
    return math.radians(deg)


def circle_area(radius):
    return round(math.pi * radius ** 2, 6)


def is_perfect_square(n):
    if n < 0:
        raise ValueError('n must be non-negative')
    root = math.isqrt(n)
    return root * root == n

